  create policy "customer manager can manage their contacts"
  on "public"."company_contacts"
  as permissive
  for all
  to authenticated
using ((EXISTS ( SELECT 1
   FROM public.user_companies
  WHERE ((user_companies.company_id = company_contacts.company_id) AND (user_companies.user_id = auth.uid())))))
with check ((EXISTS ( SELECT 1
   FROM public.user_companies
  WHERE ((user_companies.company_id = company_contacts.company_id) AND (user_companies.user_id = auth.uid())))));



  create policy "Admin can see all messages"
  on "public"."messages"
  as permissive
  for all
  to authenticated
using ((EXISTS ( SELECT 1
   FROM public.app_user
  WHERE ((auth.uid() = app_user.id) AND (app_user.role = 'admin'::public.app_role)))))
with check ((EXISTS ( SELECT 1
   FROM public.app_user
  WHERE ((auth.uid() = app_user.id) AND (app_user.role = 'admin'::public.app_role)))));



  create policy "customer_manager can see and insert messages"
  on "public"."messages"
  as permissive
  for all
  to authenticated
using ((EXISTS ( SELECT 1
   FROM (public.tickets t
     JOIN public.user_companies uc ON ((t.company_id = uc.company_id)))
  WHERE ((t.id = messages.ticket_id) AND (uc.user_id = auth.uid())))))
with check (((EXISTS ( SELECT 1
   FROM (public.tickets t
     JOIN public.user_companies uc ON ((t.company_id = uc.company_id)))
  WHERE ((t.id = messages.ticket_id) AND (uc.user_id = auth.uid())))) AND (sender_id = auth.uid())));



